/* ── INTERSECTION OBSERVER HOOK ───────────────────────── */
function useReveal(threshold = 0.12) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, visible];
}

/* ── ANIMATED COUNTER ─────────────────────────────────── */
function Counter({ end, suffix = "", duration = 1800 }) {
  const [count, setCount] = useState(0);
  const [ref, visible] = useReveal(0.4);
  useEffect(() => {
    if (!visible) return;
    let start = null;
    const raf = ts => {
      if (!start) start = ts;
      const pct = Math.min((ts - start) / duration, 1);
      const eased = 1 - Math.pow(1 - pct, 3);
      setCount(Math.floor(eased * end));
      if (pct < 1) requestAnimationFrame(raf);
    };
    requestAnimationFrame(raf);
  }, [visible, end, duration]);
  const fmt = n => n >= 1000 ? (n / 1000).toFixed(0) + "K" : n;
  return <span ref={ref}>{fmt(count)}{suffix}</span>;
}

/* ── REVEAL WRAPPER ───────────────────────────────────── */
function Reveal({ children, delay = 0, dir = "up", style: extStyle = {} }) {
  const [ref, visible] = useReveal();
  const offsets = { up:"translateY(40px)", down:"translateY(-40px)", left:"translateX(-40px)", right:"translateX(40px)", scale:"scale(0.88)" };
  return (
    <div ref={ref} style={{
      opacity: visible ? 1 : 0,
      transform: visible ? "none" : (offsets[dir] || offsets.up),
      transition: `opacity 0.7s ease ${delay}ms, transform 0.7s cubic-bezier(.22,1,.36,1) ${delay}ms`,
      ...extStyle,
    }}>
      {children}
    </div>
  );
}

